import{_ as e,o,c as a,a3 as d}from"./chunks/framework.oxq6d-og.js";const u=JSON.parse('{"title":"NHook and MinHook","description":"","frontmatter":{},"headers":[],"relativePath":"en/hooking/strategies.md","filePath":"en/hooking/strategies.md"}'),r={name:"en/hooking/strategies.md"};function n(i,t,s,c,h,l){return o(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="nhook-and-minhook" tabindex="-1">NHook and MinHook <a class="header-anchor" href="#nhook-and-minhook" aria-label="Permalink to &quot;NHook and MinHook&quot;">​</a></h1><p>Exoproc provides two inline-hook models. The choice depends on the target prologue, detour requirement, and runtime behavior you can accept.</p><table tabindex="0"><thead><tr><th>Feature</th><th>NHook</th><th>MinHook</th></tr></thead><tbody><tr><td>Patch</td><td>Two-byte <code>EB FE</code></td><td>At least a five-byte relative <code>jmp</code></td></tr><tr><td>Hit flow</td><td>Thread parks; host discovers it through <code>poll()</code></td><td>Detour runs directly in the target</td></tr><tr><td>Original prologue</td><td>Supported instructions are simulated by the host</td><td>Relocated into a trampoline</td></tr><tr><td>Detour</td><td>Built-in JS hit/resume model</td><td>Caller-supplied address or <code>CMachineCode</code></td></tr></tbody></table><p>NHook parks a thread at the function entry and has the host resume it after processing a hit. It has no conventional trampoline, but not every prologue can be simulated. MinHook relocates sufficient instructions into a trampoline; <code>create()</code> does not patch the target, while <code>enable(detour)</code> installs the jump. A distant detour uses a near relay, and MinHook does not define how a detour communicates with JavaScript.</p>',4)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
